    val waitForConsent: Boolean? = null,
    val ingestBaseUrl: String? = null,
    val clickdBaseUrl: String? = null,
) {
    companion object {
        fun fromList(pigeonVar_list: List<Any?>): ConfigMessage {
            return ConfigMessage(
                sdkKey = pigeonVar_list[0] as String,
                sdkSecret = pigeonVar_list[1] as String?,
                appId = pigeonVar_list[2] as String?,
                logLevel = pigeonVar_list[3] as String?,
                waitForConsent = pigeonVar_list[4] as Boolean?,
                ingestBaseUrl = pigeonVar_list[5] as String?,
                clickdBaseUrl = pigeonVar_list[6] as String?,
            )
        }
    }

    fun toList(): List<Any?> =
        listOf(sdkKey, sdkSecret, appId, logLevel, waitForConsent, ingestBaseUrl, clickdBaseUrl)
}

