private open class MessagesPigeonCodec : StandardMessageCodec() {
    override fun readValueOfType(type: Byte, buffer: ByteBuffer): Any? {
        return when (type) {
            129.toByte() -> (readValue(buffer) as? List<Any?>)?.let { ConfigMessage.fromList(it) }
            130.toByte() -> (readValue(buffer) as? List<Any?>)?.let { ConsentMessage.fromList(it) }
            131.toByte() -> (readValue(buffer) as? List<Any?>)?.let { AttributionMessage.fromList(it) }
            132.toByte() -> (readValue(buffer) as? List<Any?>)?.let { DeepLinkMessage.fromList(it) }
            133.toByte() -> (readValue(buffer) as? List<Any?>)?.let { NativeAdMediaMessage.fromList(it) }
            134.toByte() -> (readValue(buffer) as? List<Any?>)?.let { NativeAdMessage.fromList(it) }
            135.toByte() -> (readValue(buffer) as? List<Any?>)?.let { UpdateMessage.fromList(it) }
            136.toByte() -> (readValue(buffer) as? List<Any?>)?.let { AppMessageMessage.fromList(it) }
            else -> super.readValueOfType(type, buffer)
        }
    }

    override fun writeValue(stream: ByteArrayOutputStream, value: Any?) {
        when (value) {
            is ConfigMessage -> {
                stream.write(129)
                writeValue(stream, value.toList())
            }
            is ConsentMessage -> {
                stream.write(130)
                writeValue(stream, value.toList())
            }
            is AttributionMessage -> {
                stream.write(131)
                writeValue(stream, value.toList())
            }
            is DeepLinkMessage -> {
                stream.write(132)
                writeValue(stream, value.toList())
            }
            is NativeAdMediaMessage -> {
                stream.write(133)
                writeValue(stream, value.toList())
            }
            is NativeAdMessage -> {
                stream.write(134)
                writeValue(stream, value.toList())
            }
            is UpdateMessage -> {
                stream.write(135)
                writeValue(stream, value.toList())
            }
            is AppMessageMessage -> {
                stream.write(136)
                writeValue(stream, value.toList())
            }
            else -> super.writeValue(stream, value)
        }
    }
}

/** Host API: Dart -> native. Implemented by the plugin. */
interface MtrackerHostApi {
    fun initialize(config: ConfigMessage)
    fun requestTrackingConsent(callback: (Result<String>) -> Unit)
    fun setConsent(consent: ConsentMessage)
    fun trackEvent(name: String, params: Map<String?, Any?>)
    fun loadAd(slotId: String, callback: (Result<NativeAdMessage?>) -> Unit)
    fun getConfigJson(key: String, callback: (Result<String?>) -> Unit)
    fun setPushConsent(granted: Boolean)
    fun setPushToken(token: String)

    companion object {
        /** The codec used by MtrackerHostApi. */
        val codec: MessageCodec<Any?> by lazy { MessagesPigeonCodec() }

        /** Sets up an instance of `MtrackerHostApi` to handle messages through `binaryMessenger`. */
        fun setUp(
            binaryMessenger: BinaryMessenger,
            api: MtrackerHostApi?,
            messageChannelSuffix: String = "",
        ) {
            val separatedMessageChannelSuffix =
                if (messageChannelSuffix.isNotEmpty()) ".$messageChannelSuffix" else ""
            run {
                val channel = BasicMessageChannel<Any?>(
                    binaryMessenger,
                    "dev.flutter.pigeon.mtracker.MtrackerHostApi.initialize$separatedMessageChannelSuffix",
                    codec,
                )
                if (api != null) {
                    channel.setMessageHandler { message, reply ->
                        val args = message as List<Any?>
                        val configArg = args[0] as ConfigMessage
                        val wrapped: List<Any?> = try {
                            api.initialize(configArg)
                            listOf(null)
                        } catch (exception: Throwable) {
                            wrapError(exception)
                        }
                        reply.reply(wrapped)
                    }
                } else {
                    channel.setMessageHandler(null)
                }
            }
            run {
                val channel = BasicMessageChannel<Any?>(
                    binaryMessenger,
                    "dev.flutter.pigeon.mtracker.MtrackerHostApi.requestTrackingConsent$separatedMessageChannelSuffix",
                    codec,
                )
                if (api != null) {
                    channel.setMessageHandler { _, reply ->
                        api.requestTrackingConsent { result: Result<String> ->
                            val error = result.exceptionOrNull()
                            if (error != null) {
                                reply.reply(wrapError(error))
                            } else {
                                reply.reply(wrapResult(result.getOrNull()))
                            }
                        }
                    }
                } else {
                    channel.setMessageHandler(null)
                }
            }
            run {
                val channel = BasicMessageChannel<Any?>(
                    binaryMessenger,
                    "dev.flutter.pigeon.mtracker.MtrackerHostApi.setConsent$separatedMessageChannelSuffix",
                    codec,
                )
                if (api != null) {
                    channel.setMessageHandler { message, reply ->
                        val args = message as List<Any?>
                        val consentArg = args[0] as ConsentMessage
                        val wrapped: List<Any?> = try {
                            api.setConsent(consentArg)
                            listOf(null)
                        } catch (exception: Throwable) {
                            wrapError(exception)
                        }
                        reply.reply(wrapped)
                    }
                } else {
                    channel.setMessageHandler(null)
                }
            }
            run {
                val channel = BasicMessageChannel<Any?>(
                    binaryMessenger,
                    "dev.flutter.pigeon.mtracker.MtrackerHostApi.trackEvent$separatedMessageChannelSuffix",
                    codec,
                )
                if (api != null) {
                    channel.setMessageHandler { message, reply ->
                        val args = message as List<Any?>
                        val nameArg = args[0] as String
                        @Suppress("UNCHECKED_CAST")
                        val paramsArg = args[1] as Map<String?, Any?>
                        val wrapped: List<Any?> = try {
                            api.trackEvent(nameArg, paramsArg)
                            listOf(null)
                        } catch (exception: Throwable) {
                            wrapError(exception)
                        }
                        reply.reply(wrapped)
                    }
                } else {
                    channel.setMessageHandler(null)
                }
            }
            run {
                val channel = BasicMessageChannel<Any?>(
                    binaryMessenger,
                    "dev.flutter.pigeon.mtracker.MtrackerHostApi.loadAd$separatedMessageChannelSuffix",
                    codec,
                )
                if (api != null) {
                    channel.setMessageHandler { message, reply ->
                        val args = message as List<Any?>
                        val slotIdArg = args[0] as String
                        api.loadAd(slotIdArg) { result: Result<NativeAdMessage?> ->
                            val error = result.exceptionOrNull()
                            if (error != null) {
                                reply.reply(wrapError(error))
                            } else {
                                reply.reply(wrapResult(result.getOrNull()))
                            }
                        }
                    }
                } else {
                    channel.setMessageHandler(null)
                }
            }
            run {
                val channel = BasicMessageChannel<Any?>(
                    binaryMessenger,
                    "dev.flutter.pigeon.mtracker.MtrackerHostApi.getConfigJson$separatedMessageChannelSuffix",
                    codec,
                )
                if (api != null) {
                    channel.setMessageHandler { message, reply ->
                        val args = message as List<Any?>
                        val keyArg = args[0] as String
                        api.getConfigJson(keyArg) { result: Result<String?> ->
                            val error = result.exceptionOrNull()
                            if (error != null) {
                                reply.reply(wrapError(error))
                            } else {
                                reply.reply(wrapResult(result.getOrNull()))
                            }
                        }
                    }
                } else {
                    channel.setMessageHandler(null)
                }
            }
            run {
                val channel = BasicMessageChannel<Any?>(
                    binaryMessenger,
                    "dev.flutter.pigeon.mtracker.MtrackerHostApi.setPushConsent$separatedMessageChannelSuffix",
                    codec,
                )
                if (api != null) {
                    channel.setMessageHandler { message, reply ->
                        val args = message as List<Any?>
                        val grantedArg = args[0] as Boolean
                        val wrapped: List<Any?> = try {
                            api.setPushConsent(grantedArg)
                            listOf(null)
                        } catch (exception: Throwable) {
                            wrapError(exception)
                        }
                        reply.reply(wrapped)
                    }
                } else {
                    channel.setMessageHandler(null)
                }
            }
            run {
                val channel = BasicMessageChannel<Any?>(
                    binaryMessenger,
                    "dev.flutter.pigeon.mtracker.MtrackerHostApi.setPushToken$separatedMessageChannelSuffix",
                    codec,
                )
                if (api != null) {
                    channel.setMessageHandler { message, reply ->
                        val args = message as List<Any?>
                        val tokenArg = args[0] as String
                        val wrapped: List<Any?> = try {
                            api.setPushToken(tokenArg)
                            listOf(null)
                        } catch (exception: Throwable) {
                            wrapError(exception)
                        }
                        reply.reply(wrapped)
                    }
                } else {
                    channel.setMessageHandler(null)
                }
            }
        }
    }
}

/** Flutter API: native -> Dart callbacks. Called by the plugin. */
class MtrackerFlutterApi(
    private val binaryMessenger: BinaryMessenger,
    private val messageChannelSuffix: String = "",
) {
    companion object {
        /** The codec used by MtrackerFlutterApi. */
        val codec: MessageCodec<Any?> by lazy { MessagesPigeonCodec() }
    }

    private val separatedMessageChannelSuffix =
        if (messageChannelSuffix.isNotEmpty()) ".$messageChannelSuffix" else ""

    fun onAttribution(dataArg: AttributionMessage, callback: (Result<Unit>) -> Unit) {
        val channelName =
            "dev.flutter.pigeon.mtracker.MtrackerFlutterApi.onAttribution$separatedMessageChannelSuffix"
        val channel = BasicMessageChannel<Any?>(binaryMessenger, channelName, codec)
        channel.send(listOf(dataArg)) {
            callback(Result.success(Unit))
        }
    }

    fun onDeepLink(dataArg: DeepLinkMessage, callback: (Result<Unit>) -> Unit) {
        val channelName =
            "dev.flutter.pigeon.mtracker.MtrackerFlutterApi.onDeepLink$separatedMessageChannelSuffix"
        val channel = BasicMessageChannel<Any?>(binaryMessenger, channelName, codec)
        channel.send(listOf(dataArg)) {
            callback(Result.success(Unit))
        }
    }

    fun onUpdateAvailable(dataArg: UpdateMessage, callback: (Result<Unit>) -> Unit) {
        val channelName =
            "dev.flutter.pigeon.mtracker.MtrackerFlutterApi.onUpdateAvailable$separatedMessageChannelSuffix"
        val channel = BasicMessageChannel<Any?>(binaryMessenger, channelName, codec)
        channel.send(listOf(dataArg)) {
            callback(Result.success(Unit))
        }
    }

    fun onMessage(dataArg: AppMessageMessage, callback: (Result<Unit>) -> Unit) {
        val channelName =
            "dev.flutter.pigeon.mtracker.MtrackerFlutterApi.onMessage$separatedMessageChannelSuffix"
        val channel = BasicMessageChannel<Any?>(binaryMessenger, channelName, codec)
        channel.send(listOf(dataArg)) {
            callback(Result.success(Unit))
        }
    }
}
